/**
 * Options for the paths function.
 */
type PathsOptions = {
    /**
     * If true, returns empty array instead of throwing on invalid paths.
     * @default false
     */
    hideExceptions?: boolean;
};
/**
 * Get the normalized paths of nodes matching a JSONPath expression.
 *
 * Returns RFC 9535 normalized path format using single quotes for name selectors.
 *
 * @param payload - The JSON document to query
 * @param path - JSONPath expression string
 * @param options - Options
 * @returns Array of normalized path strings
 *
 * @example
 * ```typescript
 * // Simple property
 * paths({ a: { b: 1 } }, '$.a.b'); // => ["$['a']['b']"]
 *
 * // Array index
 * paths([1, 2, 3], '$[1]'); // => ['$[1]']
 *
 * // Wildcard
 * paths({ a: 1, b: 2 }, '$.*'); // => ["$['a']", "$['b']"]
 *
 * // Filter
 * paths([{ id: 1 }, { id: 2 }], '$[?(@.id == 1)]'); // => ['$[0]']
 *
 * // Recursive descent
 * paths({ a: { b: { c: 1 } } }, '$..c'); // => ["$['a']['b']['c']"]
 * ```
 *
 * @throws {JSONPathSyntaxError} If path is invalid (unless hideExceptions is true)
 */
declare const paths: (payload: unknown, path: string, options?: PathsOptions) => string[];

/**
 * Options for the query function.
 */
type QueryOptions = {
    /**
     * If true, returns undefined/empty array instead of throwing on invalid paths.
     * @default false
     */
    hideExceptions?: boolean;
    /**
     * If true, always returns results as an array.
     * @default false
     */
    returnArray?: boolean;
};
/**
 * Query a JSON document using JSONPath expression(s).
 *
 * @param payload - The JSON document to query
 * @param paths - JSONPath expression string or array of expressions
 * @param options - Query options
 * @returns Matched value(s), undefined if no match, or empty array with returnArray option
 *
 * @example
 * ```typescript
 * // Single value
 * query({ a: { b: 1 } }, '$.a.b'); // => 1
 *
 * // Array of values
 * query([1, 2, 3], '$[*]'); // => [1, 2, 3]
 *
 * // Filter expression
 * query([{ id: 1 }, { id: 2 }], '$[?(@.id == 1)]'); // => [{ id: 1 }]
 *
 * // With returnArray option
 * query({ a: 1 }, '$.a', { returnArray: true }); // => [1]
 *
 * // Multiple paths
 * query({ a: 1, b: 2 }, ['$.a', '$.b']); // => [1, 2]
 * ```
 *
 * @throws {JSONPathSyntaxError} If path is invalid (unless hideExceptions is true)
 */
declare const query: (payload: unknown, paths: string | string[], options?: QueryOptions) => unknown;

/**
 * JSONPath syntax error class.
 *
 * Thrown when parsing an invalid JSONPath expression.
 */
/**
 * Error thrown when a JSONPath expression has invalid syntax.
 *
 * @example
 * ```typescript
 * import { parse, JSONPathSyntaxError } from 'jsonpathly';
 *
 * try {
 *   parse('$[invalid');
 * } catch (e) {
 *   if (e instanceof JSONPathSyntaxError) {
 *     console.log(`Syntax error at line ${e.line}, column ${e.charPositionInLine}`);
 *     console.log(e.message);
 *   }
 * }
 * ```
 */
declare class JSONPathSyntaxError extends Error {
    /** Line number where the error occurred (1-based) */
    line: number;
    /** Column position where the error occurred (1-based) */
    charPositionInLine: number;
    /** The error message */
    msg: string;
    name: string;
    constructor(line: number, charPositionInLine: number, msg: string);
}

type Root = {
    type: 'root';
    next: Subscript | null;
};
type Current = {
    type: 'current';
    next: Subscript | null;
};
type ValueObject = {
    type: 'value';
    value: Record<string, unknown>;
    subtype: 'object';
};
type ValueArray = {
    type: 'value';
    value: unknown[];
    subtype: 'array';
};
type ValueString = {
    type: 'value';
    value: string;
    subtype: 'string';
};
type ValueBoolean = {
    type: 'value';
    value: boolean;
    subtype: 'boolean';
};
type ValueNumber = {
    type: 'value';
    value: number;
    subtype: 'number';
};
type ValueNull = {
    type: 'value';
    value: null;
    subtype: 'null';
};
type ValueRegex = {
    type: 'value';
    value: `/${string}/`;
    subtype: 'regex';
    opts: string;
};
type Value = ValueString | ValueBoolean | ValueNumber | ValueNull | ValueArray | ValueObject | ValueRegex;
type NotExpression = {
    type: 'notExpression';
    value: FilterExpressionContent;
};
type GroupExpression = {
    type: 'groupExpression';
    value: FilterExpressionContent;
};
type GroupOperation = {
    type: 'groupOperation';
    value: OperationContent;
};
type LogicalExpression = {
    type: 'logicalExpression';
    operator: 'or' | 'and';
    left: FilterExpressionContent;
    right: FilterExpressionContent;
};
type Slices = {
    type: 'slices';
    start: number | null;
    end: number | null;
    step: number | null;
};
type Comparator = {
    type: 'comparator';
    operator: 'eq' | 'ne' | 'lt' | 'le' | 'gt' | 'ge' | 'in' | 'nin' | 'subsetof' | 'anyof' | 'noneof' | 'size' | 'sizeof';
    left: OperationContent;
    right: OperationContent;
} | {
    type: 'comparator';
    operator: 'reg';
    left: OperationContent;
    right: ValueRegex;
} | {
    type: 'comparator';
    operator: 'empty';
    left: OperationContent;
    right: null;
};
type DotContent = Identifier | NumericLiteral | Wildcard;
type Dot = {
    type: 'dot';
    value: DotContent;
};
type DotDotContent = Identifier | Wildcard | BracketMember | BracketExpression;
type DotDot = {
    type: 'dotdot';
    value: DotDotContent;
};
type BracketMemberContent = Identifier | NumericLiteral | StringLiteral;
type BracketExpressionContent = Wildcard | FilterExpression | Slices | Unions;
type BracketExpression = {
    type: 'bracketExpression';
    value: BracketExpressionContent;
};
type BracketMember = {
    type: 'bracketMember';
    value: BracketMemberContent;
};
type Subscript = {
    type: 'subscript';
    value: Dot | DotDot | BracketMember | BracketExpression;
    next: Subscript | null;
};
type Wildcard = {
    type: 'wildcard';
};
type StringLiteral = {
    type: 'stringLiteral';
    value: string;
};
type Identifier = {
    type: 'identifier';
    value: string;
};
type NumericLiteral = {
    type: 'numericLiteral';
    value: number;
};
type Unions = {
    type: 'unions';
    values: (StringLiteral | Identifier | NumericLiteral | Wildcard)[];
};
type FunctionCall = {
    type: 'functionCall';
    name: 'length' | 'count' | 'match' | 'search' | 'value';
    args: OperationContent[];
};
type FilterExpressionContent = Comparator | GroupExpression | LogicalExpression | NotExpression | FunctionCall | Current | Root | Value;
type FilterExpression = {
    type: 'filterExpression';
    value: FilterExpressionContent;
};
type OperationContent = Root | Current | Value | GroupOperation | Operation | FunctionCall;
type Operation = {
    type: 'operation';
    operator: 'plus' | 'minus' | 'multi' | 'div';
    left: OperationContent;
    right: OperationContent;
};
type JsonPathElement = ValueObject | ValueString | ValueBoolean | ValueArray | ValueNumber | ValueNull | ValueRegex | Root | Current | NotExpression | GroupOperation | GroupExpression | LogicalExpression | Slices | Comparator | Dot | DotDot | BracketMember | BracketExpression | Subscript | Wildcard | StringLiteral | Identifier | NumericLiteral | Unions | FilterExpression | FunctionCall | Operation;

/**
 * Options for the parse function.
 */
type ParseOptions = {
    /**
     * If true, returns null instead of throwing on invalid paths.
     * @default false
     */
    hideExceptions?: boolean;
};
/**
 * Parse a JSONPath expression into an Abstract Syntax Tree (AST).
 *
 * The AST can be used for analysis, transformation, or passed to stringify()
 * to convert back to a string.
 *
 * @param input - JSONPath expression string
 * @param options - Parse options
 * @returns Parsed AST (Root node) or null if invalid with hideExceptions
 *
 * @example
 * ```typescript
 * // Basic parsing
 * const ast = parse('$.store.book[0].title');
 * // => { type: 'root', next: { type: 'subscript', value: { type: 'dot', ... }, ... } }
 *
 * // Check validity
 * const result = parse('invalid', { hideExceptions: true });
 * // => null
 *
 * // Round-trip with stringify
 * import { stringify } from 'jsonpathly';
 * stringify(parse('$.a.b')); // => '$.a.b'
 * ```
 *
 * @throws {JSONPathSyntaxError} If expression is invalid (unless hideExceptions is true)
 */
declare function parse(input: string, options?: ParseOptions): Root | null;

/**
 * JSONPath AST to string serialization.
 *
 * Converts parsed JSONPath AST back to string representation.
 * Uses RFC 9535 normalized format with single quotes.
 */

/**
 * Convert JSONPath AST element to string representation.
 *
 * @param input - AST element to stringify
 * @returns String representation of the JSONPath
 */
declare function stringify(input: JsonPathElement | null): string;

export { JSONPathSyntaxError, parse, paths, query, stringify };
